return items.map(item => {
  const d = item.json.body.data;

  // --- utilidades básicas ---
  const normalizeText = (txt) => {
    if (!txt) return "";
    return txt
      .toString()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-zA-Z0-9áéíóúüñ., ]/g, " ")   // genérico (sin /)
      .replace(/\s+/g, " ")
      .trim()
      .toLowerCase();
  };

  // normalizador SOLO para observaciones (permite "/"; opcionalmente "- :")
  const normalizeObs = (txt) => {
    if (!txt) return "";
    return txt
      .toString()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-zA-Z0-9áéíóúüñ., /:-]/g, " ") // <-- conserva / (y - :)
      .replace(/\s+/g, " ")
      .trim()
      .toLowerCase();
  };

  const normalizeUpper = (txt) => {
    if (!txt) return null;
    return txt
      .toString()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .trim()
      .toUpperCase();
  };

  // === Fechas: usar HOY y normalizar a comienzo de día ===
  const startOfDay = (dt) => {
    const d = new Date(dt);
    d.setHours(0, 0, 0, 0);
    return d;
  };
  const toDate = (val) => (val ? startOfDay(new Date(val)) : null);
  const diffDays = (a, b) => (a && b ? Math.round((a - b) / (1000*60*60*24)) : null);

  const hoy = startOfDay(new Date());
  const fechaInicio = toDate(d["Fecha de Inicio"]);
  const proximoCtrl = toDate(d["Próximo Control"]);

  const diasDesdeInicio = fechaInicio ? diffDays(hoy, fechaInicio) : null;
  let diasHastaControlSigned = proximoCtrl ? diffDays(proximoCtrl, hoy) : null;
  const diasHastaControlAbs = diasHastaControlSigned !== null ? diasHastaControlSigned : null;
  //const signoControl = diasHastaControlSigned !== null ? (diasHastaControlSigned < 0 ? "-" : "+") : null;

  const diasBaja = d["Días de BAJA"] ?? null;

  // --- salida normalizada ---
  const out = {
    id_control: d["id"] ?? null,
    cia: normalizeUpper(d["CIA"]),
    distrito: normalizeUpper(d["DISTRITO"]),
    base: normalizeUpper(d["Base/Of"]),
    tipo_evento: normalizeUpper(d["Tipo de Evento"]),
    fase: normalizeUpper(d["Tipo de Evento"]),
    diagnostico: normalizeText(d["Diagnóstico"]),
    observacion: normalizeObs(d["OBSERVACIONES"]), // <-- usa el normalizador que conserva "/"
    dias_desde_inicio: diasDesdeInicio,
    dias_hasta_control: diasHastaControlAbs,
    //dias_hasta_control_signo: signoControl,
    dias_baja: diasBaja >= 0 ? diasBaja : 0,
    valido: true,
    errores: []
  };

  // --- validaciones mínimas ---
  if (!out.observacion || out.observacion.length < 15) {
    out.valido = false;
    out.errores.push("Observación vacía o demasiado corta");
  }
  if (!out.diagnostico) {
    out.valido = false;
    out.errores.push("Diagnóstico faltante");
  }

  return { json: out };
});

return items.map(item => {
  // 1) Localizar el string con JSON (según tu salida)
  //    Tu ejemplo es un array con un objeto que tiene .message.content
  const root = item.json;
  const content = root?.[0]?.message?.content      // como en tu muestra
                ?? root?.message?.content
                ?? root?.data?.[0]?.message?.content
                ?? "";

  // 2) Extraer JSON (por si el modelo dejó saltos de línea)
  const match = content.match(/\{[\s\S]*\}/m);
  const jsonStr = match ? match[0] : content;

  // 3) Parsear y validar campos mínimos
  let out;
  try {
    out = JSON.parse(jsonStr);
  } catch (e) {
    return { json: { error: "JSON inválido", raw_content: content } };
  }

  const enumColores = ["Rojo", "Amarillo", "Verde"];
  const color = enumColores.includes(out.color_sugerido) ? out.color_sugerido : "Amarillo";
  const explicacion = String(out.explicacion_corta || "").slice(0, 180);
  const conf = Number.isFinite(Number(out.confianza_actual)) ? Number(out.confianza_actual) : 0.0;

  return {
    json: {
      color_sugerido: color,
      explicacion_corta: explicacion,
      confianza_actual: Number(conf.toFixed(2)),
      prediccion: String(out.prediccion || ""),
      //  conservar respuesta cruda por auditoría
      //_raw_model: root
    }
  };
});
